// PSU-MG 2025 - Objetiva (Medway)
export const PSU_MG_2025_QUESTIONS: any[] = [
  { id: "psumg_2025_001", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Mulher de 52 anos encontrava-se internada para colecistectomia videolaparoscópica. No 2º dia do pós-operatório, apresentou dispneia de início súbito e pré-síncope. PA 70/50mmHg, FC 134bpm, FR 32ipm, SpO2 86% (ar ambiente). Pele pálida e sudorética, enchimento capilar > 3s. Após ressuscitação volêmica com 1.000mL de cristaloide e oxigênio 3L/min, PA 104/64mmHg, FC 118bpm, FR 20ipm, SpO2 94%. AngioTC de tórax: falhas de enchimento nas artérias dos lobos inferiores bilateralmente. Troponina 0,34ng/mL. Ecocardiograma: dilatação e hipocontratilidade do VD. Assinale o tratamento imediato MAIS ADEQUADO:", options: ["Alteplase IV", "Enoxaparina SC", "Filtro de veia cava inferior", "Trombectomia mecânica"], correctIndex: 1 },
  { id: "psumg_2025_002", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Considerando a mesma paciente do caso anterior (TEP pós-operatório), cerca de oito meses depois, apresenta cinco episódios ao dia de evacuação com fezes líquidas, sem sangue, muco, pus ou restos alimentares, iniciados logo após a alta hospitalar, predominantemente diurnos e após refeições. Nega emagrecimento. EDA e colonoscopia normais. Hemoglobina 15,2g/dL; leucócitos 6.300/mm³; PCR 3mg/L; antitransglutaminase IgA não reagente; IgA total normal; anti-HIV não reagente; parasitológico negativo. Assinale o tratamento MAIS ADEQUADO:", options: ["Amitriptilina", "Colestiramina", "Duspatalina", "Loperamida"], correctIndex: 3 },
  { id: "psumg_2025_003", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Neurologia", text: "Mulher de 42 anos com migrânea, apresentando aura de hemiplegia, com duas crises por semana de cefaleia intensa e limitação das atividades de vida. É portadora de dismenorreia e hipertensão arterial sistêmica. Faz uso de ciproterona/etinilestradiol e losartana. Para as crises de cefaleia, usa anti-inflamatório não esteroidal. PA 152/94mmHg; FC 68bpm. Assinale a alternativa ERRADA em relação à prevenção de acidente vascular encefálico nessa paciente:", options: ["Otimizar o controle pressórico da paciente", "Prescrever tratamento para a profilaxia das crises de cefaleia", "Prescrever sumatriptano para tratamento das crises agudas", "Suspender o uso de ciproterona/etinilestradiol"], correctIndex: 2 },
  { id: "psumg_2025_004", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Hematologia", text: "Mulher de 25 anos vai ao Pronto Socorro com dor torácica ventilatório-dependente no hemitórax direito e dor nos quatro membros há dois dias, com dispneia aos mínimos esforços. Portadora de anemia falciforme SS, hemoglobina basal 9,6g/dL. Iniciou hidroxiureia há duas semanas. PA 124/82mmHg, FC 122bpm, SpO2 88% (ar ambiente), FR 24ipm, TAx 38,4°C. Taquipneia e crepitações teleinspiratórias na base do hemitórax direito. Hg 7,2g/dL; leucócitos 15.900/mm³; neutrófilos 13.430/mm³; PCR 45mg/L. Assinale a alternativa que apresenta uma conduta INADEQUADA:", options: ["Prescrever ceftriaxona e azitromicina IV", "Realizar transfusão de concentrado de hemácias", "Solicitar angioTC do tórax", "Suspender hidroxiureia"], correctIndex: 3 },
  { id: "psumg_2025_005", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Hematologia", text: "Homem de 62 anos queixa-se de dispneia, dor torácica aos esforços e astenia por duas semanas. Portador de hipertensão arterial e doença renal crônica (creatinina basal 2,9mg/dL; clearance 24mL/min/1,73m²). Hemoglobina 6,4g/dL; VCM 75fL; HCM 25pg; CHCM 29g/dL; RDW 16,5%; leucócitos 6.500/mm³; neutrófilos 3.560/mm³; ferritina 20pmol/L; saturação de transferrina 6%. Assinale a alternativa que apresenta uma conduta inicial INADEQUADA:", options: ["Prescrição de eritropoietina", "Prescrição de sal férrico parenteral", "Solicitação de endoscopia digestiva alta e colonoscopia", "Transfusão de concentrado de hemácias"], correctIndex: 0 },
  { id: "psumg_2025_006", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Reumatologia", text: "Homem de 55 anos queixa-se de dor, edema e calor na 1ª articulação metatarsofalangeana esquerda há dois dias, sem febre. Portador de doença renal crônica (clearance de creatinina 18mL/min/1,73m²). Uso de furosemida, carbonato de cálcio e alopurinol há mais de um ano. PA 120/78mmHg, FC 84bpm, FR 16ipm. Vermelhidão, calor e limitação de movimento na articulação, sem derrame significativo. Leucócitos 6.800/mm³; neutrófilos 3.560/mm³; PCR 16mg/L; ácido úrico 4,5mg/dL. Assinale a conduta MAIS ADEQUADA:", options: ["Prescrever ibuprofeno", "Prescrever prednisona", "Realizar artrocentese diagnóstica", "Suspender alopurinol"], correctIndex: 1 },
  { id: "psumg_2025_007", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Mulher de 56 anos vai ao Pronto Socorro com mal estar e hiporexia há três dias. Portadora de cirrose hepática por hepatite C crônica, uso de furosemida, espironolactona e carvedilol. PA 104/64mmHg, FC 55bpm, Tax 36,2°C. Submacicez dos flancos, palpação indolor. Leucócitos 6.780/mm³; creatinina 1,6mg/dL (basal 0,7mg/dL); ureia 54mg/dL; PCR 4mg/L. Assinale a alternativa que apresenta uma conduta inicial INADEQUADA:", options: ["Administração de albumina pela via IV", "Prescrição de terlipressina pela via IV", "Realização de paracentese diagnóstica", "Suspensão do carvedilol"], correctIndex: 1 },
  { id: "psumg_2025_008", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Homem de 61 anos queixa-se de dor torácica à esquerda em aperto ao subir morros e durante estresse emocional, associada a dispneia, com melhora em até 5 minutos da interrupção do esforço. É obeso, tabagista e portador de asma brônquica, com sibilos expiratórios difusos. O ECG revela hipertrofia ventricular esquerda. Assinale o achado auscultatório que pode ser encontrado ao exame físico por causa da anormalidade observada no ECG:", options: ["Desdobramento constante e variável de B2", "Desdobramento paradoxal de B2", "Hiperfonese de B1", "Hipofonese de B2"], correctIndex: 1 },
  { id: "psumg_2025_009", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cardiologia", text: "Considerando o mesmo paciente de 61 anos com dor torácica típica de angina, obeso, tabagista, asmático, com hipertrofia ventricular esquerda ao ECG, assinale o teste inicial ADEQUADO para a propedêutica da dor torácica nesse paciente:", options: ["AngioTC de coronárias", "Cineangiocoronariografia", "Cintilografia de perfusão miocárdica com dipiridamol", "Teste ergométrico"], correctIndex: 0 },
  { id: "psumg_2025_010", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Endocrinologia", text: "Homem de 54 anos queixa-se de formigamento nas mãos e nos pés e fraqueza generalizada. Realizou tireoidectomia total há duas semanas por bócio multinodular, uso de levotiroxina 150mcg/dia. Contratura carpal após 3 minutos de insuflação do manguito acima da PA sistólica (sinal de Trousseau). Cálcio total 7,3mg/dL; fósforo 5,4mg/dL; albumina 4,3g/dL. Assinale a alternativa que apresenta uma complicação que NÃO ocorre devido ao distúrbio metabólico apresentado:", options: ["Insuficiência cardíaca", "Laringoespasmo", "Osteoporose", "Síndrome rígido-acinética"], correctIndex: 2 },
  { id: "psumg_2025_011", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pneumologia", text: "Mulher de 28 anos queixa-se de dispneia aos esforços há três semanas, com picos febris de até 37,9°C, sudorese noturna profusa e perda de 3kg. Nega ortopneia, DPN ou edema periférico. TC de tórax: derrame pleural moderado à esquerda e linfonodomegalias mediastinais, parênquima pulmonar normal, sem derrame pericárdico. Líquido pleural: aspecto límpido, LDH 60U/L, proteínas 2,4g/dL, células 134/mm³, hemácias ausentes, células atípicas ausentes; sangue: LDH 168U/L, proteínas totais 7,2g/dL. Assinale o diagnóstico diferencial MAIS PROVÁVEL:", options: ["Insuficiência cardíaca congestiva", "Linfoma", "Lupus eritematoso sistêmico", "Tuberculose pleural"], correctIndex: 1 },
  { id: "psumg_2025_013", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Assinale a alternativa que apresenta um contexto em que a terapia anti-retroviral NÃO deve ser iniciada em até sete dias do primodiagnóstico da infecção pelo HIV.", options: ["Paciente apresentando tuberculose pulmonar em início de tratamento específico", "Paciente assintomático com contagem de CD4 > 500/mm³", "Paciente com criptococose meníngea em início de tratamento específico", "Paciente portador de cirrose hepática por coinfecção com vírus da hepatite B"], correctIndex: 2 },
  { id: "psumg_2025_014", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Geriatria", text: "Homem de 89 anos é levado pelos familiares com queixa de perda de memória, dificuldade de concentração e esquecimento de nomes e palavras. Apresenta insônia, vários despertares noturnos, noctúria e sonolência diurna. Exame físico sem anormalidades. Mini-exame do estado mental com pontuação 21, baixa para a escolaridade. Vitamina B12 387pg/mL; TSH 8,8mcUI/mL; T4 livre 1,3ng/dL; sorologia para Treponema pallidum IgG reagente; anti-HIV não reagente. Assinale a conduta inicial INADEQUADA em relação ao manejo das queixas cognitivas:", options: ["Prescrever inibidor da colinesterase", "Prescrever levotiroxina", "Solicitar polissonografia", "Solicitar punção lombar"], correctIndex: 0 },
  { id: "psumg_2025_015", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Gastroenterologia", text: "Mulher de 45 anos vai ao Pronto Socorro com dor há 12h no andar superior do abdome, intensa, associada a náuseas e vômitos, piora após a alimentação. Desconhece comorbidades. PA 130/92mmHg, FC 128bpm, FR 22ipm, SpO2 98%. Palpação dolorosa do andar superior do abdome, sem irritação peritoneal. Hemoglobina 16,7g/dL; leucócitos 13.450/mm³; neutrófilos 9.880/mm³; plaquetas 156.000/mm³; PCR 56mg/L; creatinina 1,5mg/dL; ureia 89mg/dL; amilase 590U/L; lipase 134U/L. Assinale a prescrição inicial INADEQUADA:", options: ["Dieta oral suspensa", "Meropenem IV", "Morfina IV", "Ressuscitação volêmica com solução cristaloide"], correctIndex: 1 },
  { id: "psumg_2025_016", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente de 70 anos, sexo feminino, traz TC de abdome feita por lombalgia, evidenciando nódulo hipervascular no colo do pâncreas de 1,9cm. Nega outros sintomas, sente-se bem, mas está apreensiva com a possibilidade de câncer de pâncreas. Dentre as opções, assinale a conduta CORRETA:", options: ["Indicar a enucleação do nódulo.", "Indicar a realização de ecoendoscopia com punção/biópsia do nódulo.", "Indicar a realização de pancreatectomia central com preservação do baço.", "Tranquilizar a paciente e acompanhá-la com exames de imagem em seis meses."], correctIndex: 1 },
  { id: "psumg_2025_017", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente de 72 anos, submetido a gastrectomia total há cinco dias, inicia agitação e confusão mental, taquipneia (30irpm), drenagem de secreção de mau cheiro pela ferida operatória, alteração aguda de 5 pontos no escore SOFA, necessitando vasopressores para PAM ≥ 65mmHg e lactato de 7mmol/L mesmo após reposição volêmica adequada. O diagnóstico MAIS PRECISO é:", options: ["Choque séptico", "Resposta orgânica ao trauma exacerbado", "Sepse", "Síndrome da Resposta Inflamatória Sistêmica"], correctIndex: 0 },
  { id: "psumg_2025_018", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "PCF, 58 anos, engenheira, relata empachamento pós-prandial há cerca de um mês, com ingestão de quantidade muito pequena de alimentos, emagrecimento de 5kg. Massa palpada no epigástrio e QSE. TC de abdome: tumoração sólida retroperitoneal ovóide de 18cm, heterogênea, com aspecto de conter gordura macroscópica, comprimindo e desviando o estômago e deslocando cólon transverso e rim, sem invasão local ou metástase. Assinale a alternativa ERRADA:", options: ["A laparotomia mediana é uma boa via de acesso cirúrgico para a resolução desse caso.", "A maioria das tumorações primárias de retroperitônio é benigna.", "Não se deve recomendar biópsia percutânea da lesão para diagnóstico diferencial.", "O melhor tratamento para essa lesão é a excisão cirúrgica completa."], correctIndex: 1 },
  { id: "psumg_2025_019", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Em relação aos pacientes com hipocalemia, é CORRETO afirmar:", options: ["A correção intravenosa da hipocalemia deve ser feita geralmente com uma taxa de 40-60 mmol/hora.", "A hipermagnesemia crônica é responsável por cerca de 40% dos casos de hipocalemia refratária ao tratamento.", "A hipocalemia causa infradesnivelamento do segmento ST, depressão da onda T e o aparecimento da onda U.", "Dosagem de potássio urinário < 20mEq/L sugere etiologia renal como causa da hipocalemia."], correctIndex: 2 },
  { id: "psumg_2025_020", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Na fase inicial da REMIT (Resposta Endócrino, Metabólica e Imunológica ao Trauma), ocorrem várias alterações metabólicas e imunológicas. É CORRETO afirmar:", options: ["A excreção de potássio na urina está reduzida devido à liberação aumentada de aldosterona.", "A liberação do hormônio do crescimento está aumentada.", "O lactato produzido perifericamente é convertido em glicose devido ao processo de glicogênese.", "Observa-se aumento da síntese da albumina."], correctIndex: 1 },
  { id: "psumg_2025_021", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente de 67 anos, submetido a colectomia parcial há cinco dias, iniciou distensão abdominal importante, taquicardia, taquipneia, hipotensão arterial e sonolência. Gasometria: pH 7,18; PaCO2 36mmHg; PaO2 70mmHg; HCO3 13mEq/L; BE 12mEq/l; Na 135mEq/L; K 2,8mEq/L; Cl 97mEq/L. Qual o distúrbio ácido-base apresentado pelo paciente?", options: ["Acidose metabólica com anion gap aumentado", "Acidose metabólica com ânion gap normal", "Acidose mista com anion gap aumentado", "Acidose mista com ânion gap normal"], correctIndex: 2 },
  { id: "psumg_2025_022", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "DBD, 17 anos, apresentou dor periumbilical com inapetência e náusea ontem; hoje dor no quadrante inferior direito, temperatura axilar 37,8°C, sem defesa abdominal, dor à palpação profunda, sem dor à descompressão. Hiperextensão da coxa direita provoca dor lombar e em fossa ilíaca direita. Leucócitos 12.050/mm³ com 6% de bastonetes. Assinale a alternativa ERRADA:", options: ["A tomografia de abdome sem contraste é o melhor exame para diagnóstico diferencial neste caso.", "É improvável que a radiografia simples de abdome traga elementos diagnósticos decisivos.", "O quadro clínico sugere apendicite aguda, embora não seja a apresentação clássica.", "Os achados de laboratório sugerem um quadro infeccioso agudo."], correctIndex: 0 },
  { id: "psumg_2025_023", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Sobre a dissecção cirúrgica durante a colecistectomia videolaparoscópica nas colecistites agudas, é CORRETO afirmar:", options: ["A causa mais comum de lesão de ducto biliar é a presença de variações congênitas da anatomia da região do pedículo biliar.", "As lesões vasculares e ductais mais graves ocorrem após a conversão de colecistectomia laparoscópica para colecistectomia aberta.", "Ducto biliar aberrante anterior esquerdo é um achado de identificação difícil e frequentemente responsável por lesões intraoperatórias.", "O triângulo hepatocístico é uma referência essencial na interpretação da anatomia correta, formado pelo ducto cístico inferiormente, pela superfície do fígado superiormente e pelo ducto hepático comum lateralmente."], correctIndex: 1 },
  { id: "psumg_2025_024", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Mulher, 37 anos, sem comorbidades, realizou USG abdominal para dor pélvica bem localizada e mal caracterizada. O exame revelou cisto ovariano de médio tamanho sem sinais de complicação e colecistolitíase (cálculo único de 3cm), sem dilatação de vias biliares. Em relação ao caso clínico, assinale a alternativa CORRETA:", options: ["Considerando que a sintomatologia deve se referir ao cisto ovariano, paciente só deve ser orientada em relação a este achado ecográfico.", "Mesmo sendo a paciente jovem e assintomática, está formalmente indicada litotripsia extracorpórea no tratamento da litíase biliar.", "Paciente deve ser orientada em relação à história natural da litíase biliar e aos benefícios e riscos da colecistectomia videolaparoscópica.", "Para se definir a melhor conduta, é imprescindível a paciente realizar previamente colangiorressonância ou ecoendoscopia."], correctIndex: 2 },
  { id: "psumg_2025_025", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente de 52 anos apresenta aumento cervical anterior com nódulo tireoidiano. USG revela nódulo sólido de 3cm com microcalcificações. PAAF sugere malignidade. Assinale a alternativa que apresenta o tipo MAIS COMUM de câncer de tireoide associado a esses achados:", options: ["Carcinoma anaplásico de tireoide", "Carcinoma folicular de tireoide", "Carcinoma medular de tireoide", "Carcinoma papilífero de tireoide"], correctIndex: 3 },
  { id: "psumg_2025_026", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "WEF, 42 anos, bancária, com disfagia progressiva há seis anos, iniciada apenas para sólidos e progredindo até dificuldade de ingestão de água, com perda ponderal de três quilos nos últimos seis meses. Sobre a propedêutica e os achados possíveis, qual afirmativa está ERRADA:", options: ["A esofagoscopia é o exame principal, pois permite avaliar diretamente a função peristáltica do esôfago.", "A impedanciometria esofágica pode auxiliar na avaliação, mostrando a distensibilidade do órgão durante a deglutição.", "A manometria esofágica é um exame importante que pode demonstrar o relaxamento incompleto do esfíncter esofagiano inferior.", "O esofagograma baritado é pouco invasivo e pode demonstrar estenose na porção distal e retardo do esvaziamento."], correctIndex: 0 },
  { id: "psumg_2025_027", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Mulher de 28 anos, faxineira, IMC 42kg/m², busca tratamento para obesidade mórbida, com tentativas frustradas de perda de peso. Apresenta HAS e SAOS controladas, diabetes controlada com medicação oral, distúrbio de ansiedade, passado de alcoolismo. Após avaliação multidisciplinar, é sugerida cirurgia bariátrica. Qual condição representa uma CONTRAINDICAÇÃO RELATIVA que deve ser cuidadosamente considerada?", options: ["Diagnóstico de transtorno de ansiedade não controlado.", "Histórico de alcoolismo em abstinência há 6 meses.", "Nível de escolaridade baixo, dificultando a adesão a orientações pós-operatórias.", "Presença de diabetes mellitus tipo 2 controlada com medicação oral."], correctIndex: 0 },
  { id: "psumg_2025_028", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Paciente de 65 anos traz USG do abdome realizada para controle de cálculo renal, evidenciando nódulo hipoecogênico no lobo esquerdo do fígado, de 3,2cm, sugestivo de hemangioma. Sem queixas, relata ingestão de bebidas alcoólicas quase diariamente há vários anos. Qual deve ser a conduta MAIS ADEQUADA?", options: ["Informar o paciente que o hemangioma é lesão benigna e não será necessário acompanhamento.", "Informar o paciente que o hemangioma é lesão benigna mas que será necessário acompanhamento com ultrassonografia a cada seis meses.", "Solicitar biópsia hepática guiada por ultrassom do nódulo hepático.", "Solicitar exame de imagem com contraste venoso, exames laboratoriais para avaliação da função hepática e dosagem de alfa-fetoproteína."], correctIndex: 3 },
  { id: "psumg_2025_029", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "Em relação aos tumores de pele, assinale a alternativa CORRETA:", options: ["Como princípio básico da cirurgia para tratamento do carcinoma espinocelular, o cirurgião deve evitar margens muito amplas, devendo ser o mais econômico possível.", "Pacientes com carcinoma espinocelular T0 e T1 diagnosticados em biópsia incisional não podem ser tratados com curetagem e cauterização pelos péssimos índices de sucesso.", "O carcinoma espinocelular tem prevalência menor em pacientes transplantados em uso de imunossupressor, já que a medicação inibe o crescimento do tumor.", "Os tumores que se desenvolvem em cicatrizes de queimaduras geralmente comportam-se de maneira mais agressiva com maior índice de metástases."], correctIndex: 3 },
  { id: "psumg_2025_030", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Cirurgia Geral", text: "PVRG, 72 anos, portador de volumosa hérnia inguinal à direita com episódios eventuais de dor em cólica, redutível com manobras manuais. É tabagista, com diabetes, obesidade e hipertrofia prostática. Assinale a assertiva que apresenta uma orientação ERRADA:", options: ["Deverá ser utilizada tela para reduzir os riscos de recidiva.", "Deverá suspender o tabagismo por período mínimo de dois meses e fazer avaliação urológica no período pré-operatório para reduzir os riscos de recidiva.", "Já que consegue reduzir o conteúdo herniário com manobras manuais e tem várias comorbidades, é mais seguro evitar a cirurgia.", "Deve tentar reduzir o peso e controlar o diabetes para prevenção de infecção do sítio cirúrgico."], correctIndex: 2 },
  { id: "psumg_2025_031", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Em relação às doenças autoimunes que podem acometer crianças e adolescentes, está CORRETA a afirmação:", options: ["A dermatomiosite juvenil é prevalente em adolescentes do sexo masculino, diagnosticada a partir de lesões de pele e fraqueza muscular, podendo se correlacionar com câncer na vida adulta.", "A hepatite autoimune e colangite esclerosante primária são diagnosticadas na maior porcentagem dos casos devido a complicações de cirrose hepática.", "A tireoidite de Hashimoto em crianças e adolescentes pode resultar em redução do crescimento, atraso no desenvolvimento esquelético e puberdade tardia.", "O lúpus eritematoso sistêmico tem quadro mais leve em crianças e adolescentes quando comparado a adultos, com menor comprometimento do SNC."], correctIndex: 2 },
  { id: "psumg_2025_032", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Criança de 5 anos e 6 meses compareceu à UBS para consulta de rotina. Alimentação baseada em arroz, batata, macarrão e frango ou ovo, sem legumes, verduras ou frutas. Gosta de doces e salgadinhos industrializados. Peso 29kg (Escore-Z entre +2 e +3), estatura 116cm (Escore-Z entre 0 e +1), IMC 21,5 (Escore-Z = 3). Diante do caso e considerando os distúrbios nutricionais na infância, é CORRETO afirmar que:", options: ["A avaliação pôndero estatural indica que a intervenção deve ser baseada em restringir os carboidratos até que ocorra perda de peso para o escore-Z zero.", "A seletividade alimentar justifica a conduta de iniciar reposição medicamentosa de ferro, vitamina A e vitamina D.", "O diagnóstico de obesidade grave torna necessário recomendar prática de atividades físicas, bem como avaliação laboratorial de perfil lipídico e glicêmico.", "O transtorno alimentar restritivo evitativo é diagnóstico provável nesse caso, sendo importante a avaliação laboratorial de anemia ferropriva e deficiência de oligoelementos."], correctIndex: 2 },
  { id: "psumg_2025_033", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Em relação à educação de crianças em situações especiais é ERRADO afirmar:", options: ["Crianças e adolescentes têm direito a monitor na sala de aula", "É uma meta a ser atingida que o aluno se adapte ao sistema educacional vigente", "O atendimento deve ocorrer preferencialmente na rede regular de ensino", "Os professores devem realizar cursos de capacitação para melhor integração desses alunos"], correctIndex: 1 },
  { id: "psumg_2025_034", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Filomena, 12 meses, previamente saudável, apresenta diarreia líquida há sete dias, fezes volumosas, sem sangue, eliminadas de forma explosiva, com distensão abdominal e assadura perianal importante. Pesa 6kg, levemente enoftálmica, com sede, diurese diminuída, perfusão de extremidades de quatro segundos. Em uso de dieta normal para a idade. Qual deve ser a conduta inicial MAIS ADEQUADA em relação à hidratação?", options: ["Solução fisiológica endovenosa 0,9%- 20ml/Kg, correr livre.", "Solução glicofisiológica endovenosa 1:1- 50ml/Kg- correr em 1 hora", "Solução de reidratação oral por gastróclise", "Terapia de reidratação oral"], correctIndex: 3 },
  { id: "psumg_2025_035", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Considerando a mesma criança de 12 meses (Filomena) com diarreia líquida há sete dias, distensão abdominal e assadura perianal importante, dentre as medidas terapêuticas, a MAIS INDICADA para o tratamento é:", options: ["Manter a dieta e prescrever probiótico por cinco dias", "Prescrever antimicrobiano, azitromicina por três dias", "Substituir a fórmula à base de proteína do leite de vaca por hidrolisado proteico", "Suspender temporariamente a lactose da dieta"], correctIndex: 3 },
  { id: "psumg_2025_036", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ética Médica", text: "Sobre o Decreto n.º 11.074/2022 (Protege Brasil), programa de proteção integral da criança e do adolescente, assinale a alternativa ERRADA:", options: ["A violência sexual intrafamiliar requer uma proposta de trabalho interdisciplinar da equipe de saúde por suas múltiplas implicações no âmbito pessoal, familiar, social e legal.", "É dever de todos os cidadãos prevenir a ocorrência de ameaça ou violação dos direitos da criança e do adolescente em todos os ambientes de convívio.", "O afastamento de criança ou adolescente do convívio familiar para proteção de vítimas de violência ou abuso sexual é de competência do Conselho Tutelar e de autoridade policial.", "O artigo 5º do ECA prevê que nenhuma criança ou adolescente será objeto de qualquer forma de negligência, discriminação, exploração, violência, crueldade ou opressão."], correctIndex: 2 },
  { id: "psumg_2025_037", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Considerando as diretrizes da American Heart Association 2020 para o Suporte Básico e Avançado de Vida em Pediatria, assinale a alternativa ERRADA:", options: ["Crianças com miocardite aguda acompanhada de arritmias, bloqueio cardíaco, alterações do segmento ST ou baixo débito cardíaco têm alto risco de PCR, sendo necessária a transferência rápida para UTI.", "Durante e após o atendimento da PCR, o paciente pode apresentar hipertensão pulmonar, sendo indicado sedar e evitar a intubação traqueal, mantendo-se leve acidemia.", "O uso rotineiro de pressão cricoide não é recomendado durante a intubação endotraqueal de pacientes pediátricos, pois reduz as taxas de sucesso da intubação e não reduz a taxa de regurgitação.", "Quando houver recursos disponíveis, o monitoramento contínuo por eletroencefalografia é recomendado para detecção de convulsões depois de uma PCR em pacientes com encefalopatia persistente."], correctIndex: 1 },
  { id: "psumg_2025_038", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Criança de 4 anos, no Pronto Atendimento, há dois dias com febre alta, inapetência, vômitos e dor abdominal aguda em cólica, com piora ao deambular e piora progressiva. Os pais pensam em apendicite. Considerando as causas de dor abdominal aguda na infância, assinale a alternativa ERRADA:", options: ["Apendicite aguda é a causa mais comum de dor abdominal de indicação cirúrgica em lactentes, sendo o diagnóstico difícil face à apresentação atípica.", "A radiografia simples de abdome pode mostrar sinais de alerta como apagamento do músculo psoas no QID, alça sentinela, níveis líquidos, massa intra-abdominal e fecalito.", "Em crianças menores de 3 anos, devido à dificuldade em diagnosticar apendicite, a taxa de perfuração é alta, ocorrendo geralmente nas primeiras 48 horas após o início dos sintomas.", "Os escores de Alvarado e o PAS utilizam elementos da história clínica, exame físico e exames laboratoriais para identificação de pacientes com alta probabilidade de apendicite."], correctIndex: 0 },
  { id: "psumg_2025_039", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente de 12 meses em atenção primária, com cartão de vacina em dia, apresenta há quatro meses diarreia com fezes volumosas semilíquidas ou pastosas 4-5 vezes ao dia, sem muco ou sangue, com redução do ganho ponderal. Recebeu leite materno até os 6 meses, depois introduzidos alimentos incluindo leite de vaca e glúten. Anemia ferropriva leve, hipoalbuminemia discreta, leucócitos fecais positivos. Baseando-se no caso, é considerada ERRADA a alternativa:", options: ["A presença de leucócitos nas fezes é um exame inespecífico e pode ser indicativo de processo inflamatório do intestino, observado em várias afecções.", "Fezes volumosas e de aspecto mais claro sugerem acometimento de intestino delgado, enquanto a presença de muco ou sangue geralmente provém de afecções do cólon.", "Marcadores bioquímicos podem auxiliar a avaliar o grau de desnutrição e indicar o tipo de abordagem terapêutica e nutricional.", "O teste de retirada da proteína do leite de vaca e seus derivados da dieta, por quatro semanas, pode permitir o diagnóstico, sem necessidade do teste de provocação oral."], correctIndex: 3 },
  { id: "psumg_2025_040", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Criança de 3 anos e 6 meses em unidade de atenção primária. Mãe apreensiva com atraso na linguagem. Qual dos parâmetros abaixo NÃO É considerado um marco de desenvolvimento adequado à idade:", options: ["Consegue fazer perguntas simples como 'qual seu nome?'", "Consegue identificar quantitativos: grande, pequeno e muito.", "Consegue nomear objetos com os quais tem contato mais frequente.", "Consegue pronunciar cerca de 20 palavras e entender cerca de 50."], correctIndex: 3 },
  { id: "psumg_2025_041", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Lactente masculino, 2 meses e meio, com 'chieira' intermitente e hoje dificuldade respiratória. Acianótico, dificuldade respiratória leve, SpO2 95% em ar ambiente. Ausculta com sibilos esparsos e sopro holossistólico ao longo da borda esternal esquerda. Fígado palpado a 2cm do rebordo costal direito. O diagnóstico MAIS PROVÁVEL é:", options: ["Comunicação interventricular", "Forame oval patente", "Persistência do canal arterial", "Síndrome de Eisenmenger"], correctIndex: 0 },
  { id: "psumg_2025_042", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Criança de 7 anos com febre há três dias, dor abdominal leve e exantema petequial em tronco, com um episódio de vômito hoje. Teste rápido para dengue positivo. Assinale a MELHOR conduta a ser instituída neste momento:", options: ["Fazer hidratação oral e coleta de hemograma, avaliando o resultado assim que disponível.", "Fazer hidratação oral e manter em observação por 48 horas na unidade de saúde.", "Fazer hidratação oral em casa e retornar à unidade de saúde no dia da melhora da febre.", "Iniciar hidratação venosa em leito de internação hospitalar com propedêutica laboratorial completa."], correctIndex: 0 },
  { id: "psumg_2025_043", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Criança de 9 anos com linfadenomegalia cervical e febre há quatro dias. Dois linfonodos cervicais anteriores de 2cm à direita e 1cm à esquerda, móveis e fibroelásticos, sem sinais flogísticos. Assinale a alternativa que contém o exame laboratorial MAIS INDICADO neste momento para o diagnóstico:", options: ["Biópsia do linfonodo com pesquisa de células neoplásicas.", "Ecocardiograma para pesquisa de coronariopatia.", "Sorologia para citomegalovírus.", "Teste rápido molecular (TRM) para tuberculose em escarro."], correctIndex: 2 },
  { id: "psumg_2025_044", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Paciente feminina, 12 anos, com cefaléia, febre e convulsões, admitida com diagnóstico de meningite. Iniciado ceftriaxone imediatamente, com punção lombar no 2º dia de tratamento. Líquor: 243 células (65% neutrófilos, 23% linfócitos, 12% monócitos), glicose 22mg/dL, proteínas 317mg/dL, Gram sem visualização de bactérias, cultura em andamento. Glicemia capilar 112mg/dL. Assinale a MELHOR CONDUTA:", options: ["Deve ser iniciada dexametasona no terceiro dia de tratamento.", "Deve ser realizada nova punção lombar para melhor esclarecimento da etiologia.", "O antibiótico deve ser mantido por 10 dias.", "O antibiótico deve ser suspenso e mantida observação clínica."], correctIndex: 2 },
  { id: "psumg_2025_045", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Paciente de 3 meses, hospitalizado com febre, coriza e tosse há quatro dias. Taquipneia (FR 62irpm), esforço respiratório leve, sibilos e crepitações difusas, SpO2 89% em ar ambiente. RX: infiltrado intersticial e hiperinsuflação. Mãe nega episódios semelhantes anteriormente. Em relação ao tratamento, assinale a alternativa CORRETA:", options: ["Iniciar broncodilatadores inalatórios e palivizumabe.", "Iniciar dieta por sonda nasogástrica e adrenalina inalatória.", "Iniciar soroterapia venosa e corticoterapia via oral.", "Iniciar oxigenioterapia e lavagem nasal com soro fisiológico."], correctIndex: 3 },
  { id: "psumg_2025_046", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Em relação aos exames complementares para diagnóstico e acompanhamento da sífilis em gestantes, assinale a alternativa CORRETA:", options: ["O rastreamento da sífilis na gestação com teste rápido deve ser realizado apenas no primeiro trimestre.", "O teste FTA-Abs é um teste treponêmico, e uma vez positivo permanece reagente por toda a vida, não sendo indicado para monitorar a resposta ao tratamento.", "O teste rápido para sífilis, disponível no SUS, pode ser utilizado tanto para diagnóstico quanto para o acompanhamento da resposta ao tratamento.", "O VDRL é um teste treponêmico que pode ser utilizado para confirmar o diagnóstico de sífilis em gestantes com testes rápidos positivos."], correctIndex: 1 },
  { id: "psumg_2025_047", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente GHS, 25 anos, primigesta, 40 semanas, no período expulsivo há 2 horas, exausta, contrações adequadas, dilatação completa, bolsa rota, feto cefálico OEA, cabeça no plano +2 de De Lee. Monitoramento fetal indica bradicardia fetal persistente de 90bpm. É CORRETO afirmar:", options: ["Indicar parto a fórceps para extração fetal, uma vez que há sinais de hipóxia intraparto e o polo cefálico profundamente encaixado dificulta e aumenta o risco da cesariana", "Indicar parto com o uso do vácuo extrator, uma vez que há sinais de hipóxia intraparto e sua segurança e efetividade na situação mostrada são superiores quando comparadas ao fórceps", "Indicar cesariana, já que a variedade de posição do polo cefálico contraindica a realização de fórceps ou vácuo extrator", "Indicar cesariana, uma vez que o fórceps não deve ser utilizado em primíparas e o vácuo extrator está contraindicado para rotação"], correctIndex: 0 },
  { id: "psumg_2025_048", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Primigesta, 17 anos, 35 semanas, PA 140x90mmHg há sete dias e cefaleia persistente desde o dia anterior. FC 92bpm, SpO2 99%, altura uterina 31cm, cardiotocografia reativa, linha de base 132bpm, feto cefálico com dorso à direita, sem contrações, colo fechado. Propedêutica de HELLP sem alterações. A conduta MAIS APROPRIADA é:", options: ["Internar para controle pressórico e realizar dopplervelocimetria fetal", "Internar para indução do parto e iniciar sulfato de magnésio", "Prescrever metildopa e encaminhar para o pré-natal de alto risco", "Prescrever nifedipina e realizar curva pressórica ambulatorial"], correctIndex: 1 },
  { id: "psumg_2025_049", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 42 anos, grávida de 38 semanas e quatro dias, admitida com queixa de contrações, acompanhada por partograma. Gestação única, feto cefálico, peso estimado 3705g. Hipertensa e diabética, gravidez por FIV, comorbidades controladas. Considerando a evolução do partograma apresentado, assinale a alternativa CORRETA:", options: ["A evolução do trabalho de parto está dentro da normalidade e, na hora de registro 8, a dilatação está completa, com rotação de ODT para OP após a rotação interna.", "A evolução do trabalho de parto está dentro da normalidade e, na hora de registro 8, o polo cefálico ainda não alcançou o plano zero de De Lee, indo de OET para OS.", "A evolução do trabalho de parto não está dentro da normalidade porque, embora a paciente esteja com dilatação de 10cm na hora de registro 8, a variedade de posição não está adequada para o nascimento.", "A evolução do trabalho de parto não está dentro da normalidade, pois não houve mudança da dilatação nas primeiras horas de registro e o polo cefálico insinuou na pelve materna transverso."], correctIndex: 0 },
  { id: "psumg_2025_050", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Em relação à inervação dos músculos do assoalho pélvico e do períneo, assinale a alternativa CORRETA:", options: ["O nervo pudendo deixa a pelve através do ligamento uterosacro", "O nervo pudendo é o principal nervo sensorial e motor do períneo", "O nervo pudendo possui quatro ramos: clitoriano, perineal, retal inferior e vesical", "Para o bloqueio do nervo pudendo a referência anatômica é o forâmen ciático"], correctIndex: 1 },
  { id: "psumg_2025_051", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Primigesta, 23 anos, 16 semanas e três dias, sem queixas, cartão de vacina atualizado. Grupo sanguíneo B Rh negativo; glicemia de jejum 91mg/dL; VDRL não reator; toxoplasmose IgM negativo, IgG positivo; hemoglobina 11,5g/dL; urina rotina com glicosúria (2+); urocultura sem crescimento; eletroforese de hemoglobina padrão AA. PA 110x80mmHg; útero-fita 15cm; BCF 142bpm; sem edemas. É conduta ADEQUADA a ser indicada nesta consulta de pré-natal:", options: ["Antecipação do teste oral de tolerância à glicose de 75g de dextrosol em 2 horas, considerando risco elevado para diabetes gestacional.", "Orientações sobre higiene e dieta para prevenção de toxoplasmose e avaliar padrão de hemoglobina paterno.", "Prescrição de ferro elementar terapêutico na dose de 160mg e reavaliação dos níveis hematimétricos após 60 dias de tratamento.", "Solicitação de Coombs indireto e agendamento de nova consulta de pré-natal em quatro semanas."], correctIndex: 3 },
  { id: "psumg_2025_052", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 32 anos, 60 dias após cesariana, com fissura em mamilo esquerdo, mama edemaciada, endurecida, com dor intensa e eritema. Dois picos febris de 39°C. Orientada por cunhada a manter aleitamento apenas na mama não fissurada. Mama esquerda com área de 5cm em quadrante supero-lateral com endurecimento, dor, calor e vermelhidão, sem trajetos fistulosos, secreção purulenta ou flutuação. Assinale o diagnóstico e a conduta CORRETOS:", options: ["Abscesso Lactacional; solicitar ultrassonografia e realizar drenagem cirúrgica.", "Ectasia Ductal; prescrever analgésicos e desobstruir o ducto.", "Mastite Lactacional; iniciar antibioticoterapia com amoxicilina ou cefalexina, além de incentivar aleitamento em ambas as mamas.", "Mastite Lactacional; iniciar antibioticoterapia com ciprofloxacino, além de incentivar aleitamento em ambas as mamas."], correctIndex: 2 },
  { id: "psumg_2025_053", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Considerando uma gestante que manipula alimentos frescos no trabalho, advertida sobre riscos de toxoplasmose no pré-natal, assinale a alternativa CORRETA sobre essa doença:", options: ["Numa gestação de 10 semanas, o resultado de avidez elevada sugere que a toxoplasmose aguda ocorreu antes da gestação.", "Para evitar a toxoplasmose deve-se afastar essa gestante da manipulação de alimentos cujo preparo envolva ovos e leite não pasteurizado.", "Teste de avidez se aplica a casos de toxoplasmose com IgM positivo e IgG negativo, para confirmar se a infecção é recente.", "Toxoplasma gondii é uma bactéria de vida intracelular obrigatória, que pode ser transmitida ao feto na gestação."], correctIndex: 0 },
  { id: "psumg_2025_054", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 45 anos, ciclos menstruais regulares, sangramento uterino anormal intermitente nos últimos seis meses. Biópsia de endométrio: hiperplasia endometrial simples sem atipias. Após exclusão de malignidade, qual seria A MELHOR ESTRATÉGIA de manejo a longo prazo, levando em conta fatores de risco para recorrência?", options: ["Ablação endometrial seguida de monitoramento anual.", "Administração contínua de progestágenos orais por seis meses.", "Inserção de sistema intrauterino de levonorgestrel (SIU-LNG).", "Tratamento com estrogênio conjugado seguido de nova biópsia."], correctIndex: 2 },
  { id: "psumg_2025_055", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Sobre dor pélvica crônica, assinale a alternativa ERRADA:", options: ["A ciclicidade da dor conforme o ciclo menstrual, a localização através de questionários validados e as escalas de dor aprimoram a avaliação na busca do diagnóstico.", "A história obstétrica deve ser anotada, embora tenha mais relevância para casos de dor aguda, sendo incomum que a paciente apresente dor pélvica ou genital crônica em consequência de partos", "A postura e a marcha são parte importante do exame físico e qualquer assimetria pode refletir distúrbios musculoesqueléticos", "Há associação significativa entre a dor pélvica crônica e o abuso físico, emocional ou sexual, devendo ser sempre pesquisados sintomas de depressão"], correctIndex: 1 },
  { id: "psumg_2025_056", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 20 anos, primigesta, 39 semanas, em trabalho de parto. Toque vaginal: colo com 10cm de dilatação, bolsa rota, feto no plano zero de De Lee, variedade de apresentação OTD, sutura sagital mais próxima à sínfise púbica e distante do sacro. Paciente não deseja analgesia. É CORRETO afirmar:", options: ["Aguardar até 1 hora para a expulsão fetal, caso não ocorra dentro deste período indicar cesariana.", "Identificado assinclitismo anterior que impossibilita o parto vaginal, devendo ser indicada cesariana de imediato.", "O assinclitismo posterior pode ser transitório, podendo-se aguardar a descida da apresentação e parto vaginal com acompanhamento da evolução.", "Por se tratar de feto em posição transversa em período expulsivo, deve ser indicado fórceps de Simpson e parto vaginal."], correctIndex: 2 },
  { id: "psumg_2025_057", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 42 anos com citologia cervical HSIL, biópsia com NIC III, submetida à conização há 45 dias, peça cirúrgica com NIC III, ausência de invasão, margens livres. A MELHOR CONDUTA para acompanhamento pós-conização é realizar:", options: ["Citologia 12 meses após o procedimento. Se negativa, passar para citologia trienal.", "Citologia 6 e 12 meses após o procedimento. Se negativas, passar para citologia anual até completar cinco anos do tratamento.", "Citologia 6, 12, 18 e 24 meses após o procedimento. Se negativas, passar para citologia trienal.", "Citologia em 3, 6, 9 e 12 meses após o procedimento. Se negativas, passar para citologia anual até completar cinco anos do tratamento."], correctIndex: 1 },
  { id: "psumg_2025_058", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Entre as alternativas abaixo, assinale aquela que NÃO apresenta fator de risco para o acretismo placentário:", options: ["Cesariana e infecção endometrial após o aborto", "Curetagem uterina e miomectomia", "Gestação por fertilização in vitro e placenta prévia", "Gravidez heterotópica e infecção do trato urinário"], correctIndex: 3 },
  { id: "psumg_2025_059", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Assinale a alternativa CORRETA quanto ao período de transição menopáusica.", options: ["Durante a fase inicial de transição menopáusica, os níveis de progesterona são mais baixos quando comparados aos de mulheres na meia idade reprodutiva, e os níveis de testosterona não variam significativamente.", "Mulheres na pós-menopausa com sangramento uterino anormal e com espessura endometrial > 4mm não têm indicação de realizar biópsia de endométrio.", "O risco de fraturas decorrente de osteoporose não depende da massa óssea no momento da menopausa, mas da taxa de perda óssea logo após a menopausa.", "Os níveis de SHBG aumentam após a menopausa, o que pode aumentar a fração livre dos esteroides; com relação ao SDHEA, é observada redução nos seus níveis com o avançar da idade"], correctIndex: 0 },
  { id: "psumg_2025_060", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ginecologia e Obstetrícia", text: "Paciente de 55 anos, hígida, menopausa aos 50 anos, com sensação de peso em baixo ventre. Prolapso de parede vaginal anterior +3cm e prolapso da posterior +2cm. Em relação a este caso, assinale a alternativa CORRETA:", options: ["O tratamento cirúrgico com colpoplastia anterior e colpoperineoplastia são suficientes para correção do prolapso, entretanto a paciente pode apresentar incontinência urinária de esforço posteriormente.", "O tratamento com mudanças de hábitos de vida e fisioterapia de assoalho pélvico tem altas taxas de sucesso neste caso.", "O uso de estrogênio tópico melhora o trofismo genital e por aumentar o tônus muscular pode reverter o prolapso.", "O uso de pessário associado a estrogenioterapia local e fisioterapia para assoalho pélvico deve ser a primeira escolha para a paciente por ser conservador e de menor risco."], correctIndex: 0 },
  { id: "psumg_2025_061", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Considerando a Portaria GM/MS Nº 3.148/2024, que estabelece a lista nacional de notificação compulsória, assinale a opção em que TODAS AS DOENÇAS são de notificação imediata, em até 24 horas nos níveis municipal, estadual e federal.", options: ["Casos de dengue, difteria, leptospirose", "Influenza humana produzida por novo subtipo viral, febre hemorrágica por ebola, tuberculose", "Malária na região extra amazônica, raiva humana, febre amarela", "Sarampo, rubéola, leishmaniose visceral"], correctIndex: 2 },
  { id: "psumg_2025_062", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Segundo a RDC nº 406/2020 da Anvisa, a farmacovigilância se refere à ciência e atividades relativas à detecção, avaliação, compreensão e prevenção de Eventos Adversos ou problemas relacionados a medicamentos. Dentre as afirmações, qual se encaixa MELHOR nesta atividade?", options: ["A farmacovigilância não aborda problemas de qualidade, uso não aprovado e abuso de medicamentos", "O Sistema Nacional de Vigilância de eventos supostamente atribuíveis à vacinação foi criado em 1992, antes da Anvisa, portanto as vacinas não estão sujeitas ao monitoramento de segurança no escopo da farmacovigilância", "O VigiMed é o sistema disponibilizado pela Anvisa para que cidadãos, profissionais de saúde e patrocinadores possam reportar suspeitas de eventos adversos relacionados apenas a medicamentos", "Os sistemas de notificação voluntária geram o maior volume de informações, com baixo custo de manutenção, e permitem identificação precoce de sinais de segurança relacionados aos medicamentos, constituindo a base dos sistemas nacionais de farmacovigilância"], correctIndex: 3 },
  { id: "psumg_2025_063", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "A Febre Reumática (FR) é a principal causa de cardiopatia adquirida entre 5 e 15 anos no Brasil. Com relação à sua prevenção, é CORRETO afirmar:", options: ["A profilaxia primária com a penicilina G benzatina previne a recorrência e a progressão da doença, além de diminuir a gravidade e a mortalidade relacionadas à doença.", "Carência de atendimento médico, condições precárias de saneamento e higiene e aglomerados populacionais estão associados à incidência de FR.", "Esforços têm sido realizados para a produção de vacinas contra o S. pyogenes, sendo facilitados pela baixa diversidade de cepas causadoras da doença.", "O tratamento precoce das faringotonsilites estreptocócicas configura importante forma de prevenção da FR; o uso da penicilina G benzatina na prevenção primária não tem apresentado resultados satisfatórios devido à resistência antibiótica."], correctIndex: 1 },
  { id: "psumg_2025_064", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Criança de 3 anos com otalgia intensa à direita, início súbito, com febre há três dias. Hiperemia importante e abaulamento da membrana timpânica direita, temperatura axilar 39,5°C. Com relação à indicação de antibioticoterapia, é CORRETO afirmar:", options: ["Deve ser adotada conduta expectante e só iniciar antibióticos se houver evolução para otorreia", "Está indicado o uso de antibióticos e pode ser utilizado amoxicilina por via oral", "Estaria recomendada somente se houvesse comprometimento bilateral", "Não está indicada, pois a maioria dos casos, considerando a faixa etária e as condições clínicas, têm melhora espontânea"], correctIndex: 1 },
  { id: "psumg_2025_065", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Sobre os princípios do Sistema Único de Saúde (SUS), considere: I. A universalidade garante que todos os cidadãos brasileiros têm direito a acesso aos serviços de saúde, independentemente de sua situação econômica ou social. II. A iniciativa privada poderá participar do SUS, em caráter complementar, devendo a prestação do serviço ser voluntária. III. A equidade defende que todos devem receber o mesmo tratamento, independentemente de suas necessidades individuais. IV. A integralidade busca garantir ao indivíduo assistência que transcenda a prática curativa, contemplando todos os níveis de atenção. Estão CORRETAS:", options: ["Apenas I e II", "Apenas I, II e IV", "Apenas I e IV", "Apenas III e IV"], correctIndex: 2 },
  { id: "psumg_2025_066", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Pediatria", text: "Ao ensinar sobre reidratação oral para crianças com diarreia, qual orientação para agentes comunitários de saúde está CORRETA?", options: ["Administrar SRO específicas para a diarreia, seguindo receitas caseiras.", "Instruir os pais a interromper a alimentação normal da criança até que a diarreia cesse completamente.", "Recomendar o uso de sucos de frutas naturais ou bebidas esportivas como substituto para soluções farmacológicas de reidratação oral.", "Reconhecer sinais de alerta: piora na diarreia (aumento da frequência e/ou do volume), vômitos repetidos, muita sede, recusa de alimentos, sangue nas fezes, diminuição da diurese."], correctIndex: 3 },
  { id: "psumg_2025_067", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "As lesões de trânsito são importante problema de saúde pública global. Sobre as lesões de trânsito no Brasil, assinale a alternativa CORRETA:", options: ["Fatores humanos são preponderantes como causa das lesões de trânsito, sendo que as condições das vias de circulação, a visibilidade e os defeitos nos veículos contribuem em pequena proporção.", "Lesões no trânsito podem ser evitadas, para isso basta que todos, pedestres e motoristas, sigam corretamente a legislação brasileira relacionada ao trânsito.", "Motoristas de automóveis e caminhões, motociclistas e ciclistas são as principais vítimas no trânsito.", "O perfil das vítimas fatais de motociclistas em lesões no trânsito é predominantemente do sexo masculino, isso porque as mulheres são mais prudentes no trânsito."], correctIndex: 0 },
  { id: "psumg_2025_068", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Estudante de 17 anos, iniciou em 30/07/2024 com tosse, cefaleia, mialgia e em 04/08/2024 apresentou exantema em todo corpo. Viajou para a Inglaterra, retornando em 28/07/2024. Não frequentou escola após o retorno. RT-PCR detectável para vírus do sarampo. Última dose de tríplice viral em 2012. Com relação a este caso é correto afirmar:", options: ["A primeira medida a ser tomada é repetir o exame de biologia molecular, porque provavelmente deve se tratar de exame falso positivo, considerando o estado vacinal do adolescente.", "Devem ser considerados contatos do caso as pessoas que estiveram próximas ao adolescente quatro dias antes e quatro dias após o início do exantema.", "Os passageiros dos mesmos voos que o paciente realizou não devem ser considerados como contatos, uma vez que durante o período da viagem ele estava assintomático.", "Os contatos do adolescente devem ser monitorados pelo período de dois meses."], correctIndex: 1 },
  { id: "psumg_2025_069", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Referência ao personagem Jeca Tatu, de Monteiro Lobato (1914), que serviu para denominar uma doença tropical negligenciada. Assinale a alternativa que apresenta CORRETAMENTE esta doença:", options: ["Amebíase", "Ancilostomíase", "Ascaridíase", "Estrongiloidíase"], correctIndex: 1 },
  { id: "psumg_2025_070", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Ética Médica", text: "FDS, 25 anos, agricultor, ingeriu composto organofosforado após desentendimento familiar, encontrado desacordado e encaminhado à unidade de emergência. ECG 2/15, sialorreia intensa, sudorese, miose, ptose palpebral, bradicardia com hipotensão. Evoluiu para óbito cerca de uma hora após a entrada. Assinale a atitude CORRETA do médico em relação à Declaração de óbito (DO):", options: ["Preencher a DO, colocando o suicídio como provável doença ou estado mórbido que causou diretamente a morte, sendo importante esta citação para fins epidemiológicos.", "Preencher a DO, colocando como condição significativa que contribuiu para a morte, não relacionada diretamente à causa do óbito, provável depressão.", "Não preencher a DO, devendo encaminhar o corpo para o Instituto Médico Legal.", "Preencher a DO, colocando como a doença ou estado mórbido que causou diretamente a morte: autointoxicação por exposição, intencional, a organofosforado."], correctIndex: 2 },
  { id: "psumg_2025_071", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "Sobre a situação da obesidade no Brasil, assinale a assertiva CORRETA:", options: ["Apresenta-se como fator de risco para as principais DCNTs mais prevalentes no Brasil (doenças cardiovasculares, diabetes, neoplasias malignas).", "Na população adulta, observa-se maior prevalência de excesso de peso e obesidade nas mulheres de melhor nível socioeconômico.", "O aumento expressivo de casos de sobrepeso e obesidade, considerado em níveis epidêmicos, se deve à ausência de políticas públicas no país de prevenção e tratamento desta condição.", "O consumo de alimentos ultraprocessados, estilo de vida ou uso de alguns medicamentos são fatores que levam à obesidade, não havendo interferência de fatores genéticos."], correctIndex: 0 },
  { id: "psumg_2025_072", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Infectologia", text: "Mulher de 66 anos, residente em município com epidemia de dengue, com febre, mal estar e cefaleia há três dias. Em uso de rivaroxabana há dois meses, por trombose venosa profunda. Desidratada, PA 120x80mmHg, FC 100bpm. Hematócrito 54,3% (VR 35-45%) e plaquetas 43.000/mm³ (VR 150.000-400.000). Sobre o atendimento desta paciente dentro da Rede de Atenção à Saúde, é CORRETO afirmar:", options: ["Deverá ser solicitada internação hospitalar em leito de enfermaria.", "Deverá ser solicitada internação hospitalar em leito de Unidade de Terapia Intensiva.", "Ela deverá ser acompanhada na UBS com agendamento de retorno diário, até 24 horas após o desaparecimento da febre, para avaliação clínica, hemograma e RNI.", "Ela deverá ser acompanhada na UBS com agendamento de retorno para reavaliação clínica no dia de melhora da febre, e caso não haja defervescência, retornar no quinto dia."], correctIndex: 0 },
  { id: "psumg_2025_073", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "São exemplos de vacinas que LEVAM SECUNDARIAMENTE À PROTEÇÃO contra o câncer, por estarem envolvidas na prevenção de agentes infecciosos ligados à carcinogênese:", options: ["Vacina inativada para poliomielite - VIP e vacina oral do rotavírus humano", "Vacina tríplice viral e tetra viral", "Vacinas contra Hepatite B e contra papilomavírus humano (HPV)", "Vacinas pneumocócicas e meningocócicas"], correctIndex: 2 },
  { id: "psumg_2025_074", banca: "PSU-MG", cycle: "Ciclo Clínico", subject: "Saúde Coletiva", text: "No período de 1980 a 2023 foram registrados mais de 1 milhão de casos de AIDS no Brasil. Sobre a situação epidemiológica da infecção pelo HIV e da AIDS no Brasil é CORRETO afirmar:", options: ["A maior concentração dos casos de AIDS no Brasil, no período de 1980 a 2023, foi observada nos indivíduos com idade entre 25 e 39 anos, com predomínio do sexo masculino.", "A taxa de detecção de HIV/AIDS em menores de 5 anos é utilizada como indicador para o monitoramento da transmissão vertical do HIV, e tem-se observado aumento na taxa de detecção nesta população nos últimos anos.", "Apesar de no início da epidemia a AIDS ter sido mais frequente em homens e em pessoas de maior nível socioeconômico, nos últimos 10 anos, o número de casos em pessoas de mais baixo nível socioeconômico e mulheres se tornou prevalente.", "Nos últimos 10 anos, todas as regiões apresentaram tendência de queda na taxa de detecção de AIDS, exceto a região Centro Oeste, na qual essa taxa se elevou em 20%."], correctIndex: 0 },
];
